css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #fffaf0; color: #2b2620; }
.navbar { display: flex; justify-content: space-between; align-items: center; padding: 24px 60px; }
.brand { font-size: 19px; font-weight: 800; }
.nav-links { display: flex; gap: 28px; }
.nav-links a { color: #9c9286; text-decoration: none; font-size: 14px; font-weight: 600; }
.nav-links a.active { color: #ec4899; }
.hero { padding: 50px 60px 60px; max-width: 760px; }
.hero h1 { font-size: 46px; font-weight: 800; line-height: 1.3; margin-bottom: 18px; }
.hero h1 span { color: #ec4899; }
.hero p { color: #9c9286; font-size: 16px; line-height: 1.7; margin-bottom: 24px; max-width: 540px; }
.hero-tags { display: flex; gap: 10px; flex-wrap: wrap; }
.tag { background: #fdeee8; color: #ec4899; padding: 7px 16px; border-radius: 999px; font-size: 12.5px; font-weight: 700; }
.gallery { padding: 20px 60px 70px; }
.filter-row { display: flex; gap: 10px; margin-bottom: 28px; flex-wrap: wrap; }
.filter { background: #fff3e9; border: 1px solid #f5e2d3; color: #9c9286; padding: 9px 18px; border-radius: 999px; font-size: 13px; font-weight: 700; cursor: pointer; }
.filter.active { background: #ec4899; color: white; border-color: #ec4899; }
.grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(200px, 1fr)); gap: 20px; }
.grid-item { aspect-ratio: 1; border-radius: 18px; display: flex; align-items: center; justify-content: center; font-size: 56px; cursor: pointer; transition: 0.2s; }
.grid-item:hover { transform: scale(1.03); }
.grid-item.c1 { background: linear-gradient(150deg, #fde2e4, #fad2e1); }
.grid-item.c2 { background: linear-gradient(150deg, #cdeac0, #b8e0d2); }
.grid-item.c3 { background: linear-gradient(150deg, #fcf6bd, #ffd6a5); }
.grid-item.c4 { background: linear-gradient(150deg, #d0f4de, #a9def9); }
.grid-item.c5 { background: linear-gradient(150deg, #e2ece9, #bee1e6); }
.grid-item.c6 { background: linear-gradient(150deg, #ffd6a5, #fdffb6); }
.process { padding: 70px 60px; background: white; }
.process h2 { font-size: 30px; font-weight: 800; text-align: center; margin-bottom: 40px; }
.process-row { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 24px; max-width: 1000px; margin: 0 auto; }
.process-step { text-align: center; }
.pnum { display: inline-flex; width: 40px; height: 40px; border-radius: 50%; background: #fdeee8; color: #ec4899; align-items: center; justify-content: center; font-weight: 800; font-size: 16px; margin-bottom: 14px; }
.process-step h3 { font-size: 16px; font-weight: 700; margin-bottom: 8px; }
.process-step p { color: #9c9286; font-size: 13px; line-height: 1.6; }
.contact { text-align: center; padding: 80px 60px; background: linear-gradient(135deg, #fdeee8, #fff3e9); }
.contact h2 { font-size: 30px; font-weight: 800; margin-bottom: 10px; }
.contact p { color: #9c9286; font-size: 14px; margin-bottom: 26px; }
.contact button { background: #ec4899; color: white; border: none; padding: 15px 32px; border-radius: 999px; font-size: 14px; font-weight: 700; cursor: pointer; }
@media (max-width: 900px) { .navbar, .hero, .gallery, .process, .contact { padding-left: 24px; padding-right: 24px; } .nav-links { display: none; } .hero h1 { font-size: 30px; } }

